"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Wrench } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";
import { ToolRead } from "./tool-read";
import { ToolWrite } from "./tool-write";
import { ToolBash } from "./tool-bash";
import { ToolSearch } from "./tool-search";
import { ToolHttp } from "./tool-http";
import { ToolEmail } from "./tool-email";
import { ToolAskUser } from "./tool-ask-user";

// ── Tool name → component map ──

const TOOL_COMPONENTS: Record<string, React.ComponentType<{ tool: ToolCallEvent }>> = {
  ask_user_question: ToolAskUser,
  read: ToolRead,
  read_attachment: ToolRead,
  write: ToolWrite,
  edit: ToolWrite,
  bash: ToolBash,
  grep: ToolSearch,
  glob: ToolSearch,
  search_web: ToolHttp,
  http_fetch: ToolHttp,
  http_download: ToolHttp,
  email_send: ToolEmail,
};

// Prefix-based matching for tools like browser_*, memory_*, etc.
const TOOL_PREFIX_COMPONENTS: { prefix: string; component: React.ComponentType<{ tool: ToolCallEvent }> }[] = [
  { prefix: "browser_", component: ToolHttp },
  { prefix: "email_", component: ToolEmail },
  { prefix: "search_", component: ToolSearch },
];

function getToolLabel(name: string) {
  return name.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
}

// ── Dispatcher ──

export function ToolCallChip({ tool }: { tool: ToolCallEvent }) {
  // Exact match
  const Exact = TOOL_COMPONENTS[tool.name];
  if (Exact) return <Exact tool={tool} />;

  // Prefix match
  for (const { prefix, component: Prefixed } of TOOL_PREFIX_COMPONENTS) {
    if (tool.name.startsWith(prefix)) return <Prefixed tool={tool} />;
  }

  // Generic fallback
  const summary = tool.arguments
    ? Object.values(tool.arguments).find((v) => typeof v === "string" && v.length > 0) as string | undefined
    : undefined;

  return (
    <ToolCallShell
      tool={tool}
      icon={Wrench}
      label={getToolLabel(tool.name)}
      summary={summary?.slice(0, 80)}
    />
  );
}

// Re-export shell for custom usage
export { ToolCallShell } from "./tool-call-shell";

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { MessageSquareMore, Check } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

interface AskUserQuestion {
  id: string;
  question: string;
  header?: string;
  options?: { label: string; description?: string }[];
}

/** Ask user question tool — shows the questions and answers after completion */
export function ToolAskUser({ tool }: { tool: ToolCallEvent }) {
  const questions = (tool.arguments?.questions || []) as AskUserQuestion[];
  const isAnswered = tool.state === "completed" || tool.state === "interrupted";

  // Try to parse the result as answers
  let answers: { questionId: string; selected: string[] }[] = [];
  if (tool.result) {
    try {
      const parsed = JSON.parse(tool.result);
      answers = parsed.answers || [];
    } catch {
      // result might be plain text — not structured
    }
  }

  return (
    <ToolCallShell
      tool={tool}
      icon={MessageSquareMore}
      label="Question"
      summary={isAnswered ? `${questions.length} answered` : `${questions.length} question${questions.length > 1 ? "s" : ""}`}
    >
      <div className="bg-gray-50 px-3 py-2 text-xs space-y-2">
        {questions.map((q) => {
          const answer = answers.find((a) => a.questionId === q.id);
          return (
            <div key={q.id} className="flex items-start gap-2">
              {isAnswered ? (
                <Check size={12} className="text-green-600 shrink-0 mt-0.5" />
              ) : (
                <MessageSquareMore size={12} className="text-blue-500 shrink-0 mt-0.5" />
              )}
              <div className="min-w-0">
                <p className="text-gray-900 font-medium">{q.question}</p>
                {answer && answer.selected.length > 0 && (
                  <p className="text-gray-400 mt-0.5">{answer.selected.join(", ")}</p>
                )}
                {!answer && isAnswered && (
                  <p className="text-gray-300 italic mt-0.5">Skipped</p>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </ToolCallShell>
  );
}

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Terminal } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

/** Bash tool — shows command and output */
export function ToolBash({ tool }: { tool: ToolCallEvent }) {
  const command = (tool.arguments?.command) as string | undefined;
  const lines = tool.result?.split("\n") || [];
  const maxLines = 10;
  const truncated = lines.length > maxLines;

  return (
    <ToolCallShell tool={tool} icon={Terminal} label="Bash" summary={command?.slice(0, 60)}>
      <div className="bg-[#1a1a1a] max-h-[220px] overflow-y-auto">
        {command && (
          <div className="px-3 py-1.5 text-[11px] font-mono text-emerald-400 border-b border-white/10">
            <span className="text-gray-500 select-none">$ </span>{command}
          </div>
        )}
        {tool.result && (
          <pre className="m-0 px-3 py-1.5 text-[11px] leading-normal font-mono text-neutral-300 whitespace-pre-wrap break-all">
            {lines.slice(0, maxLines).join("\n")}
            {truncated ? `\n… +${lines.length - maxLines} lines` : ""}
          </pre>
        )}
      </div>
    </ToolCallShell>
  );
}

"use client";

import { useState, type ReactNode } from "react";
import type { ToolCallEvent } from "@polpo-ai/sdk";
import { ChevronRight, Loader2, Check, AlertCircle, type LucideIcon } from "lucide-react";

// ── Shell props ──

export interface ToolCallShellProps {
  tool: ToolCallEvent;
  icon: LucideIcon;
  label: string;
  /** One-line summary shown next to the label */
  summary?: string | null;
  /** Custom expanded content — replaces default raw result */
  children?: ReactNode;
}

// ── Shell ──

export function ToolCallShell({ tool, icon: Icon, label, summary, children }: ToolCallShellProps) {
  const [expanded, setExpanded] = useState(false);
  const isPending = tool.state === "calling" || tool.state === "preparing";
  const isError = tool.state === "error";
  const isDone = tool.state === "completed";
  const hasContent = isDone && (children || tool.result);

  return (
    <div className={`flex flex-col rounded-lg bg-gray-100 border border-gray-200 text-[13px] text-gray-600 overflow-hidden ${isError ? "border-red-200 bg-red-50" : ""}`}>
      <button
        className={`flex items-center gap-2 px-3 py-2 border-none bg-transparent font-inherit text-inherit text-left w-full ${hasContent ? "cursor-pointer" : "cursor-default"}`}
        onClick={() => hasContent && setExpanded(!expanded)}
      >
        <Icon size={14} className="shrink-0" />
        <span className="font-medium text-gray-900 whitespace-nowrap">{label}</span>
        {summary ? <span className="text-gray-400 text-xs overflow-hidden text-ellipsis whitespace-nowrap max-w-[300px]">{summary}</span> : null}
        {isPending ? <Loader2 size={14} className="animate-spin text-blue-500 shrink-0" /> : null}
        {isDone ? <Check size={14} className="text-green-600 shrink-0" /> : null}
        {isError ? <AlertCircle size={14} className="text-red-500 shrink-0" /> : null}
        {hasContent ? (
          <ChevronRight size={12} className={`ml-auto text-gray-400 shrink-0 transition-transform duration-150 ${expanded ? "rotate-90" : ""}`} />
        ) : null}
      </button>
      {expanded ? (
        <div className="border-t border-gray-200">
          {children || (
            <pre className="m-0 px-2.5 py-2 text-[11px] leading-normal font-mono text-gray-600 bg-gray-50 whitespace-pre-wrap break-all max-h-[180px] overflow-y-auto">
              {tool.result}
            </pre>
          )}
        </div>
      ) : null}
    </div>
  );
}

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Mail } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

/** Email send tool — shows recipient, subject, and body preview */
export function ToolEmail({ tool }: { tool: ToolCallEvent }) {
  const to = (tool.arguments?.to || tool.arguments?.recipient) as string | undefined;
  const subject = (tool.arguments?.subject) as string | undefined;
  const body = (tool.arguments?.body || tool.arguments?.content) as string | undefined;
  const summary = to ? `→ ${to}` : null;

  return (
    <ToolCallShell tool={tool} icon={Mail} label="Email" summary={summary}>
      <div className="bg-gray-50 px-2.5 py-2 text-xs max-h-[180px] overflow-y-auto">
        {subject && (
          <div className="mb-1">
            <span className="text-gray-400">Subject: </span>
            <span className="text-gray-900 font-medium">{subject}</span>
          </div>
        )}
        {to && (
          <div className="mb-1.5">
            <span className="text-gray-400">To: </span>
            <span className="text-gray-600">{to}</span>
          </div>
        )}
        {body && (
          <p className="m-0 text-gray-600 leading-relaxed whitespace-pre-wrap">
            {body.slice(0, 300)}{body.length > 300 ? "…" : ""}
          </p>
        )}
      </div>
    </ToolCallShell>
  );
}

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Globe } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

/** HTTP fetch/download/search_web tool — shows URL and response preview */
export function ToolHttp({ tool }: { tool: ToolCallEvent }) {
  const url = (tool.arguments?.url) as string | undefined;
  const method = (tool.arguments?.method as string)?.toUpperCase() || "GET";
  const summary = url ? `${method} ${url}` : null;

  return (
    <ToolCallShell tool={tool} icon={Globe} label={tool.name === "search_web" ? "Search Web" : "HTTP"} summary={summary}>
      {tool.result && (
        <pre className="m-0 px-2.5 py-2 text-[11px] leading-normal font-mono text-gray-600 bg-gray-50 whitespace-pre-wrap break-all max-h-[180px] overflow-y-auto">
          {tool.result.slice(0, 500)}{tool.result.length > 500 ? "\n…" : ""}
        </pre>
      )}
    </ToolCallShell>
  );
}

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { FileText } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

/** Read tool — shows file path and truncated content with line numbers */
export function ToolRead({ tool }: { tool: ToolCallEvent }) {
  const path = (tool.arguments?.path || tool.arguments?.file_path) as string | undefined;
  const lines = tool.result?.split("\n") || [];
  const maxLines = 12;
  const truncated = lines.length > maxLines;

  return (
    <ToolCallShell tool={tool} icon={FileText} label="Read" summary={path}>
      {tool.result && (
        <div className="bg-gray-50 max-h-[220px] overflow-y-auto">
          <table className="w-full text-[11px] leading-relaxed font-mono border-collapse">
            <tbody>
              {lines.slice(0, maxLines).map((line, i) => (
                <tr key={i} className="hover:bg-gray-100/50">
                  <td className="text-right text-gray-400 select-none px-2.5 py-0 w-[1%] whitespace-nowrap">{i + 1}</td>
                  <td className="text-gray-600 px-2.5 py-0 whitespace-pre-wrap break-all">{line}</td>
                </tr>
              ))}
            </tbody>
          </table>
          {truncated && (
            <div className="px-2.5 py-1 text-[10px] text-gray-400 border-t border-gray-200">
              +{lines.length - maxLines} more lines
            </div>
          )}
        </div>
      )}
    </ToolCallShell>
  );
}

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Search, FolderSearch } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

/** Grep/Glob/Search tool — shows query/pattern and matched results */
export function ToolSearch({ tool }: { tool: ToolCallEvent }) {
  const isGlob = tool.name === "glob";
  const pattern = (tool.arguments?.pattern || tool.arguments?.query || tool.arguments?.q) as string | undefined;
  const path = (tool.arguments?.path || tool.arguments?.root) as string | undefined;
  const summary = pattern ? `${pattern}${path ? ` in ${path}` : ""}` : path;

  const lines = tool.result?.split("\n").filter(Boolean) || [];
  const maxItems = 8;
  const truncated = lines.length > maxItems;

  return (
    <ToolCallShell tool={tool} icon={isGlob ? FolderSearch : Search} label={isGlob ? "Glob" : tool.name === "grep" ? "Grep" : "Search"} summary={summary}>
      {lines.length > 0 && (
        <div className="bg-gray-50 max-h-[200px] overflow-y-auto">
          <ul className="list-none m-0 p-0">
            {lines.slice(0, maxItems).map((line, i) => (
              <li key={i} className="px-2.5 py-0.5 text-xs font-mono text-gray-600 border-b border-gray-200/50 last:border-b-0 hover:bg-gray-100/50 truncate">
                {line}
              </li>
            ))}
          </ul>
          {truncated && (
            <div className="px-2.5 py-1 text-[10px] text-gray-400 border-t border-gray-200">
              +{lines.length - maxItems} more results
            </div>
          )}
        </div>
      )}
    </ToolCallShell>
  );
}

"use client";

import type { ToolCallEvent } from "@polpo-ai/sdk";
import { Pen } from "lucide-react";
import { ToolCallShell } from "./tool-call-shell";

/** Write/Edit tool — shows file path and a diff-like preview */
export function ToolWrite({ tool }: { tool: ToolCallEvent }) {
  const path = (tool.arguments?.path || tool.arguments?.file_path) as string | undefined;
  const content = (tool.arguments?.content || tool.arguments?.new_string) as string | undefined;
  const preview = content?.slice(0, 200);

  return (
    <ToolCallShell tool={tool} icon={Pen} label={tool.name === "edit" ? "Edit" : "Write"} summary={path}>
      {preview && (
        <div className="bg-gray-50 max-h-[180px] overflow-y-auto">
          <pre className="m-0 px-2.5 py-2 text-[11px] leading-normal font-mono text-green-700 whitespace-pre-wrap break-all">
            {preview}{content && content.length > 200 ? "\n…" : ""}
          </pre>
        </div>
      )}
    </ToolCallShell>
  );
}
